# STEP 1 of 2 — Bootstrap: registers all 7 PCF controls as unmanaged in DEV
# After this succeeds, import SygnumPCFComponents_8.0.18.zip as managed (Step 2)
# You can delete SygnumPCFInit from DEV after Step 2 completes.
$b64 = ""
$bytes = [Convert]::FromBase64String($b64)
$outPath = "$env:USERPROFILE\Desktop\SygnumPCFInit_unmanaged.zip"
[System.IO.File]::WriteAllBytes($outPath, $bytes)
Write-Host "Saved to: $outPath"
Write-Host "Import as UNMANAGED in make.powerapps.com, then import SygnumPCFComponents_8.0.18.zip"